class Solution:
    def isArraySpecial(self, nums, queries):
        n = len(nums)
        res = []
        for l, r in queries:
            ok = True
            for i in range(l, r):
                if nums[i] % 2 == nums[i+1] % 2:
                    ok = False
                    break
            res.append(ok)
        return res

