class Solution:
    def isArraySpecial(self, nums, queries):
        n = len(nums)
        prefix = [0] * (n + 1)
        for i in range(1, n):
            prefix[i + 1] = prefix[i] + (1 if nums[i] % 2 == nums[i-1] % 2 else 0)
        return [prefix[r + 1] - prefix[l + 1] == 0 for l, r in queries]

