var isArraySpecial = function(nums, queries) {
    const n = nums.length;
    const prefix = new Array(n + 1).fill(0);
    for (let i = 1; i < n; i++) {
        prefix[i + 1] = prefix[i] + (nums[i] % 2 === nums[i-1] % 2 ? 1 : 0);
    }
    return queries.map(([l, r]) => prefix[r + 1] - prefix[l + 1] === 0);
};
